"use client";

import { useState } from "react";
import { ChevronDown } from "lucide-react";
import { cn } from "@/lib/utils";
import { FramedSection } from "./framed-section";

const FAQ_ITEMS = [
  {
    question: "What kind of memes can I create?",
    answer:
      "You can create image-based memes using popular templates (e.g. Drake, Change My Mind, Two Buttons). Add your own captions and branding. We focus on formats that work for launches, promos, and social.",
  },
  {
    question: "Is it suitable for my brand?",
    answer:
      "Yes. Meme Builder is built for businesses. You control the tone, add promo context, and keep everything in a library so your memes stay on brand.",
  },
  {
    question: "How fast can I get a meme?",
    answer:
      "Pick a template, add your text, and generate. Most memes are ready in seconds. You can tweak and re-download as needed.",
  },
  {
    question: "Can my team use it?",
    answer:
      "Pro and Enterprise plans include team seats. Share templates, manage a shared library, and keep campaigns consistent across the team.",
  },
];

export function FAQSection() {
  const [openId, setOpenId] = useState<number | null>(0);

  return (
    <FramedSection
      variant="default"
      backgroundVariant="faq"
      id="faq-heading"
      aria-labelledby="faq-heading"
      className="w-full"
    >
      <h2
        id="faq-heading"
        className="text-center text-2xl font-bold text-stone-900 md:text-3xl"
      >
        Frequently asked questions
      </h2>
      <p className="marketing-copy mx-auto mt-2 max-w-xl text-center">
        Quick answers to common questions.
      </p>
      <div className="mt-10 space-y-2">
        {FAQ_ITEMS.map((item, i) => (
          <div
            key={i}
            className="rounded-xl border border-stone-200 bg-white/80 shadow-sm"
          >
            <button
              type="button"
              onClick={() => setOpenId(openId === i ? null : i)}
              className="flex w-full items-center justify-between gap-4 px-5 py-4 text-left"
              aria-expanded={openId === i}
            >
              <span className="font-medium text-stone-900">{item.question}</span>
              <ChevronDown
                className={cn(
                  "h-5 w-5 shrink-0 text-stone-500 transition-transform",
                  openId === i && "rotate-180"
                )}
              />
            </button>
            <div
              className={cn(
                "overflow-hidden transition-all",
                openId === i ? "max-h-64 opacity-100" : "max-h-0 opacity-0"
              )}
            >
              <p className="marketing-copy border-t border-stone-200 px-5 py-4 text-sm">
                {item.answer}
              </p>
            </div>
          </div>
        ))}
      </div>
    </FramedSection>
  );
}
